create extension if not exists pgcrypto;
create type public.app_role as enum ('member','moderator','admin');
create type public.content_status as enum ('draft','published','archived');
create table public.profiles(id uuid primary key references auth.users(id) on delete cascade,username text unique not null check(char_length(username) between 3 and 32),display_name text,bio text check(char_length(bio)<=500),avatar_url text,role public.app_role not null default 'member',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.species_categories(id bigint generated always as identity primary key,name text unique not null,slug text unique not null);
create table public.species(id uuid primary key default gen_random_uuid(),category_id bigint not null references public.species_categories,common_name text not null,scientific_name text unique not null,slug text unique not null,care_level text not null,lifespan text,adult_size text,temperature text,humidity text,feeding text,habitat text,morph_information text,cover_url text,status public.content_status not null default 'draft',created_by uuid references public.profiles,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.article_categories(id bigint generated always as identity primary key,name text unique not null,slug text unique not null);
create table public.articles(id uuid primary key default gen_random_uuid(),category_id bigint references public.article_categories,title text not null,slug text unique not null,excerpt text,body text not null,cover_url text,status public.content_status not null default 'draft',author_id uuid references public.profiles,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),published_at timestamptz);
create table public.tags(id bigint generated always as identity primary key,name text unique not null,slug text unique not null);
create table public.article_tags(article_id uuid references public.articles on delete cascade,tag_id bigint references public.tags on delete cascade,primary key(article_id,tag_id));
create table public.article_species(article_id uuid references public.articles on delete cascade,species_id uuid references public.species on delete cascade,primary key(article_id,species_id));
create table public.forum_categories(id bigint generated always as identity primary key,name text unique not null,slug text unique not null);
create table public.posts(id uuid primary key default gen_random_uuid(),author_id uuid not null references public.profiles on delete cascade,category_id bigint references public.forum_categories,species_id uuid references public.species,title text not null,body text not null,image_url text,is_locked boolean not null default false,is_hidden boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.replies(id uuid primary key default gen_random_uuid(),post_id uuid not null references public.posts on delete cascade,author_id uuid not null references public.profiles on delete cascade,parent_id uuid references public.replies on delete cascade,body text not null,is_hidden boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.post_likes(post_id uuid references public.posts on delete cascade,user_id uuid references public.profiles on delete cascade,created_at timestamptz not null default now(),primary key(post_id,user_id));
create table public.saved_articles(user_id uuid references public.profiles on delete cascade,article_id uuid references public.articles on delete cascade,created_at timestamptz not null default now(),primary key(user_id,article_id));
create table public.favorite_species(user_id uuid references public.profiles on delete cascade,species_id uuid references public.species on delete cascade,created_at timestamptz not null default now(),primary key(user_id,species_id));
create table public.species_gallery(id uuid primary key default gen_random_uuid(),species_id uuid references public.species on delete cascade,url text not null,alt_text text,position int not null default 0);
create index species_category_idx on public.species(category_id);create index articles_category_published_idx on public.articles(category_id,published_at desc) where status='published';create index posts_created_idx on public.posts(created_at desc) where is_hidden=false;create index posts_author_idx on public.posts(author_id);create index replies_post_created_idx on public.replies(post_id,created_at);create index post_likes_user_idx on public.post_likes(user_id);
create or replace function public.set_updated_at() returns trigger language plpgsql set search_path='' as $$begin new.updated_at=now();return new;end$$;
create trigger profiles_updated before update on public.profiles for each row execute function public.set_updated_at();create trigger species_updated before update on public.species for each row execute function public.set_updated_at();create trigger articles_updated before update on public.articles for each row execute function public.set_updated_at();create trigger posts_updated before update on public.posts for each row execute function public.set_updated_at();
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path='' as $$begin insert into public.profiles(id,username,display_name) values(new.id,coalesce(new.raw_user_meta_data->>'username','keeper_'||substr(new.id::text,1,8)),new.raw_user_meta_data->>'display_name');return new;end$$;revoke all on function public.handle_new_user() from public;create trigger on_auth_user_created after insert on auth.users for each row execute function public.handle_new_user();
create or replace function public.is_admin() returns boolean language sql stable security definer set search_path='' as $$select exists(select 1 from public.profiles where id=(select auth.uid()) and role in('admin','moderator'))$$;revoke all on function public.is_admin() from public;grant execute on function public.is_admin() to authenticated;
alter table public.profiles enable row level security;alter table public.species_categories enable row level security;alter table public.species enable row level security;alter table public.article_categories enable row level security;alter table public.articles enable row level security;alter table public.tags enable row level security;alter table public.article_tags enable row level security;alter table public.article_species enable row level security;alter table public.forum_categories enable row level security;alter table public.posts enable row level security;alter table public.replies enable row level security;alter table public.post_likes enable row level security;alter table public.saved_articles enable row level security;alter table public.favorite_species enable row level security;alter table public.species_gallery enable row level security;
create policy "public profiles readable" on public.profiles for select to anon,authenticated using(true);create policy "owners update profile" on public.profiles for update to authenticated using((select auth.uid())=id) with check((select auth.uid())=id);
create policy "published species readable" on public.species for select to anon,authenticated using(status='published' or public.is_admin());create policy "admins manage species" on public.species for all to authenticated using(public.is_admin()) with check(public.is_admin());create policy "published articles readable" on public.articles for select to anon,authenticated using(status='published' or public.is_admin());create policy "admins manage articles" on public.articles for all to authenticated using(public.is_admin()) with check(public.is_admin());
create policy "posts readable" on public.posts for select to anon,authenticated using(not is_hidden or public.is_admin());create policy "members create posts" on public.posts for insert to authenticated with check((select auth.uid())=author_id);create policy "owners update posts" on public.posts for update to authenticated using((select auth.uid())=author_id or public.is_admin()) with check((select auth.uid())=author_id or public.is_admin());create policy "owners delete posts" on public.posts for delete to authenticated using((select auth.uid())=author_id or public.is_admin());
create policy "replies readable" on public.replies for select to anon,authenticated using(not is_hidden or public.is_admin());create policy "members create replies" on public.replies for insert to authenticated with check((select auth.uid())=author_id);create policy "owners manage replies" on public.replies for update to authenticated using((select auth.uid())=author_id or public.is_admin()) with check((select auth.uid())=author_id or public.is_admin());
create policy "likes readable" on public.post_likes for select to anon,authenticated using(true);create policy "own likes insert" on public.post_likes for insert to authenticated with check((select auth.uid())=user_id);create policy "own likes delete" on public.post_likes for delete to authenticated using((select auth.uid())=user_id);
create policy "own saves" on public.saved_articles for all to authenticated using((select auth.uid())=user_id) with check((select auth.uid())=user_id);create policy "own favorites" on public.favorite_species for all to authenticated using((select auth.uid())=user_id) with check((select auth.uid())=user_id);
create policy "reference categories readable" on public.species_categories for select to anon,authenticated using(true);create policy "article categories readable" on public.article_categories for select to anon,authenticated using(true);create policy "forum categories readable" on public.forum_categories for select to anon,authenticated using(true);create policy "tags readable" on public.tags for select to anon,authenticated using(true);create policy "article tags readable" on public.article_tags for select to anon,authenticated using(true);create policy "article species readable" on public.article_species for select to anon,authenticated using(true);create policy "gallery readable" on public.species_gallery for select to anon,authenticated using(true);
grant select on public.profiles,public.species_categories,public.species,public.article_categories,public.articles,public.tags,public.article_tags,public.article_species,public.forum_categories,public.posts,public.replies,public.post_likes,public.species_gallery to anon,authenticated;grant insert,update,delete on public.posts,public.replies,public.post_likes,public.saved_articles,public.favorite_species to authenticated;grant select on public.saved_articles,public.favorite_species to authenticated;grant update on public.profiles to authenticated;grant usage,select on all sequences in schema public to anon,authenticated;
insert into storage.buckets(id,name,public,file_size_limit,allowed_mime_types) values('media','media',true,5242880,array['image/jpeg','image/png','image/webp']) on conflict(id) do nothing;create policy "media public read" on storage.objects for select to anon,authenticated using(bucket_id='media');create policy "users upload own media" on storage.objects for insert to authenticated with check(bucket_id='media' and (storage.foldername(name))[1]=(select auth.uid())::text);create policy "users update own media" on storage.objects for update to authenticated using(bucket_id='media' and owner_id=(select auth.uid()::text)) with check(bucket_id='media' and owner_id=(select auth.uid()::text));create policy "users delete own media" on storage.objects for delete to authenticated using(bucket_id='media' and owner_id=(select auth.uid()::text));
